/* Tymczasowy synchroniczny loader pdf-lib + fontkit dla Kalkulator/test.html.
 * Docelowo ten plik powinien zostać podmieniony na pełny lokalny build pdf-lib,
 * fontkit oraz lokalny font, jeżeli test ma działać offline.
 */
(function installPdfPreviewWaitingMessagePatch(){
  const oldMessage = 'Generating PDF preview...';
  const newMessage = 'The Machine Canticle is rendering the PDF preview...';

  if (window.__wngPdfPreviewWaitingMessagePatchInstalled) return;
  window.__wngPdfPreviewWaitingMessagePatchInstalled = true;

  const originalOpen = window.open;
  window.open = function patchedWindowOpen(){
    const openedWindow = originalOpen.apply(window, arguments);

    try {
      if (openedWindow && openedWindow.document && typeof openedWindow.document.write === 'function') {
        const originalWrite = openedWindow.document.write.bind(openedWindow.document);
        openedWindow.document.write = function patchedDocumentWrite(markup){
          if (typeof markup === 'string') markup = markup.replace(oldMessage, newMessage);
          return originalWrite(markup);
        };
      }
    } catch (error) {
      // Jeżeli przeglądarka zablokuje dostęp do okna, eksport PDF i tak obsłuży błąd we własnym logu.
    }

    return openedWindow;
  };
})();

(function loadPdfLibAndFontkitSynchronously(){
  if (!window.PDFLib) {
    document.write('<script src="https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js"><\/script>');
  }

  if (!window.fontkit) {
    document.write('<script src="https://cdn.jsdelivr.net/npm/@pdf-lib/fontkit@1.1.1/dist/fontkit.umd.min.js"><\/script>');
  }
})();

(function installColumnPdfExportForTestPage(){
  if (window.__wngColumnPdfExportInstalled) return;
  window.__wngColumnPdfExportInstalled = true;

  const FONT_URL = 'https://cdn.jsdelivr.net/gh/notofonts/noto-fonts@main/hinted/ttf/NotoSans/NotoSans-Regular.ttf';
  const STORAGE_WARNING_ID = 'pdfLogMessage';

  const ATTRIBUTES = [
    { key: 'S', label: 'S' },
    { key: 'Wt', label: 'Wt' },
    { key: 'Zr', label: 'Zr' },
    { key: 'I', label: 'I' },
    { key: 'SW', label: 'SW' },
    { key: 'Int', label: 'Int' },
    { key: 'Ogd', label: 'Ogd' },
    { key: 'Speed', label: 'Szybkość' }
  ];

  const SKILLS = [
    { key: 'analysis', attr: 'Int', pdf: 'Analiza', sum: 'AnalizaSuma' },
    { key: 'athletics', attr: 'S', pdf: 'Atletyka', sum: 'AtletykaSuma' },
    { key: 'awareness', attr: 'Int', pdf: 'Czujność', sum: 'CzujnośćSuma' },
    { key: 'leadership', attr: 'SW', pdf: 'Dowodzenie', sum: 'DowodzenieSuma' },
    { key: 'insight', attr: 'Ogd', pdf: 'Intuicja', sum: 'IntuicjaSuma' },
    { key: 'tech', attr: 'Int', pdf: 'Technologia', sum: 'TechnologiaSuma' },
    { key: 'medicae', attr: 'Int', pdf: 'Medycyna', sum: 'MedycynaSuma' },
    { key: 'psychicMastery', attr: 'SW', pdf: 'Psionika', sum: 'PsionikaSuma' },
    { key: 'deception', attr: 'Ogd', pdf: 'Oszukiwanie', sum: 'OszukiwanieSuma' },
    { key: 'persuasion', attr: 'Ogd', pdf: 'Perswazja', sum: 'PerswazjaSuma' },
    { key: 'pilot', attr: 'Zr', pdf: 'Pilotaż', sum: 'PilotażSuma' },
    { key: 'cunning', attr: 'Ogd', pdf: 'Przebiegłość', sum: 'PrzebiegłośćSuma' },
    { key: 'survival', attr: 'SW', pdf: 'Przetrwanie', sum: 'PrzetrwanieSuma' },
    { key: 'stealth', attr: 'Zr', pdf: 'Ukrywanie się', sum: 'Ukrywanie sięSuma' },
    { key: 'ballisticSkill', attr: 'Zr', pdf: 'Umiejętności strzeleckie', sum: 'Umiejętności StrzeleckieSuma' },
    { key: 'weaponSkill', attr: 'I', pdf: 'Walka Wręcz', sum: 'Walka WręczSuma' },
    { key: 'scholar', attr: 'Int', pdf: 'Wiedza ogólna', sum: 'Wiedza ogólnaSuma' },
    { key: 'intimidation', attr: 'SW', pdf: 'Zastraszanie', sum: 'ZastraszanieSuma' }
  ];

  const SIZE_DEFENCE_BONUS = {
    'Malutki': 2,
    'Mały': 1,
    'Średni': 0,
    'Duży': 0,
    'Ogromny': 0,
    'Monstrualny': 0
  };

  const CORRUPTION_SLOTS = Array.from({ length: 25 }, function(_, i){ return 'Check Box ' + (i + 1); });
  const CORRUPTION_LEVEL_SLOTS = ['Check Box 26', 'Check Box 27', 'Check Box 28', 'Check Box 29', 'Check Box 30'];

  const ABILITY_FIELD_NAMES = [
    'Zdolności i talenty 1',
    'Zdolności i talenty 2',
    'Zdolności i talenty 3',
    'Zdolności i talenty 4',
    'Zdolności i talenty 5',
    'Zdolności i talenty 6',
    'Zdolności i talenty 7',
    'Zdolności i talenty 8'
  ];

  const COLUMN_AREAS = {
    abilitiesAndTalents: {
      pageIndex: 0,
      x: 40,
      y: 578,
      width: 530,
      height: 118,
      minColumns: 2,
      maxColumns: 4,
      maxFontSize: 10,
      minFontSize: 5,
      label: 'Zdolności i Talenty'
    },
    notes: {
      pageIndex: 0,
      x: 25,
      y: 40,
      width: 410,
      height: 135,
      minColumns: 2,
      maxColumns: 4,
      maxFontSize: 10,
      minFontSize: 5,
      label: 'Notatki'
    },
    background: {
      pageIndex: 0,
      x: 467,
      y: 623,
      width: 109,
      height: 39,
      minColumns: 1,
      maxColumns: 3,
      maxFontSize: 8,
      minFontSize: 4,
      label: 'Przeszłość'
    }
  };

  function $(id){ return document.getElementById(id); }
  function toInt(value, fallback){
    const n = parseInt(value, 10);
    return Number.isFinite(n) ? n : fallback;
  }
  function clamp(value, min, max){ return Math.max(min, Math.min(max, value)); }
  function minOne(value){ return Math.max(1, Math.ceil(Number(value) || 0)); }
  function minZero(value){ return Math.max(0, Math.ceil(Number(value) || 0)); }
  function pad2(value){ return String(value).padStart(2, '0'); }
  function esc(text){
    return String(text || '').replace(/[&<>"']/g, function(m){
      return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' })[m];
    });
  }
  function buildPdfFileName(languageCode){
    const d = new Date();
    return languageCode + '-' + d.getFullYear() + '-' + pad2(d.getMonth() + 1) + '-' + pad2(d.getDate()) + '-' + pad2(d.getHours()) + pad2(d.getMinutes()) + '.pdf';
  }

  function setPdfLog(message, level){
    const el = $(STORAGE_WARNING_ID);
    if (!el) return;
    el.textContent = message || 'No PDF messages.';
    el.classList.remove('is-error');
    if (level === 'error') el.classList.add('is-error');
  }

  function showPreviewError(previewWindow, message){
    if (!previewWindow || previewWindow.closed) return;
    previewWindow.document.open();
    previewWindow.document.write('<!doctype html><html><head><meta charset="utf-8"><title>PDF Preview Error</title></head><body style="margin:24px;background:#000;color:#ffdada;font-family:Consolas,monospace;white-space:pre-wrap;">' + esc(message) + '</body></html>');
    previewWindow.document.close();
  }

  function getAttributes(){
    const result = {};
    ATTRIBUTES.forEach(function(attr){
      const input = $('attr_' + attr.key);
      result[attr.key] = input ? clamp(toInt(input.value, attr.key === 'Speed' ? 6 : 1), 1, 12) : (attr.key === 'Speed' ? 6 : 1);
    });
    return result;
  }

  function getSkills(){
    const result = {};
    SKILLS.forEach(function(skill){
      const input = $('skill_' + skill.key);
      result[skill.key] = input ? clamp(toInt(input.value, 0), 0, 8) : 0;
    });
    return result;
  }

  function getSkillTotals(attrs, skillValues){
    const result = {};
    SKILLS.forEach(function(skill){
      result[skill.key] = (skillValues[skill.key] || 0) + (attrs[skill.attr] || 0);
    });
    return result;
  }

  function getTalents(){
    const talents = [];
    document.querySelectorAll('[id^="talent_name_"]').forEach(function(textarea){
      const index = textarea.id.replace('talent_name_', '');
      const costInput = $('talent_cost_' + index);
      talents.push({
        name: textarea.value || '',
        cost: costInput ? Math.max(0, toInt(costInput.value, 0)) : 0
      });
    });
    return talents;
  }

  function getSpecialRules(){
    return Array.from(document.querySelectorAll('#specialRulesTable tr[data-rule-index]')).map(function(row){
      const i = row.dataset.ruleIndex;
      const type = $('rule_type_' + i);
      const name = $('rule_name_' + i);
      const target = $('rule_target_' + i);
      const value = $('rule_value_' + i);
      return {
        type: type ? type.value : 'other',
        name: name ? name.value : '',
        target: target ? target.value : 'none',
        value: value ? toInt(value.value, 0) : 0
      };
    });
  }

  function getCharacter(){
    return {
      gameTier: clamp(toInt(($('character_gameTier') || {}).value, 1), 1, 5),
      speciesName: (($('character_speciesName') || {}).value || '').trim(),
      size: (($('character_size') || {}).value || 'Średni'),
      factionName: (($('character_factionName') || {}).value || '').trim(),
      archetypeName: (($('character_archetypeName') || {}).value || '').trim(),
      keywords: (($('character_keywords') || {}).value || '').trim()
    };
  }

  function getBonusByTarget(rules){
    const bonus = {};
    rules.forEach(function(rule){
      if (rule.target && rule.target !== 'none') {
        bonus[rule.target] = (bonus[rule.target] || 0) + (Number(rule.value) || 0);
      }
    });
    return bonus;
  }

  function computeData(){
    const attrs = getAttributes();
    const skillValues = getSkills();
    const skillTotals = getSkillTotals(attrs, skillValues);
    const character = getCharacter();
    const rules = getSpecialRules();
    const bonus = getBonusByTarget(rules);
    const sizeBonus = SIZE_DEFENCE_BONUS[character.size] || 0;
    const influenceSelect = $('derived_influenceAttribute');
    const influenceBase = influenceSelect ? influenceSelect.value : 'Ogd';
    const corruptionInput = $('derived_corruptionBase');
    const corruptionBase = corruptionInput ? toInt(corruptionInput.value, 0) : 0;

    const raw = {
      woundsMax: attrs.Wt + 2 * character.gameTier + (bonus.woundsMax || 0),
      shock: attrs.SW + character.gameTier + (bonus.shock || 0),
      determination: attrs.Wt + (bonus.determination || 0),
      defence: attrs.I - 1 + sizeBonus + (bonus.defence || 0),
      resilience: attrs.Wt + 1 + (bonus.resilience || 0),
      resolve: attrs.SW + (bonus.resolve || 0),
      conviction: attrs.SW - 1 + (bonus.conviction || 0),
      influence: (attrs[influenceBase] || attrs.Ogd) - 1 + (bonus.influence || 0),
      wealth: character.gameTier + (bonus.wealth || 0),
      corruption: corruptionBase + (bonus.corruption || 0),
      speed: attrs.Speed + (bonus.speed || 0),
      passiveAwareness: Math.ceil((skillTotals.awareness || 0) / 2)
    };

    return {
      raw: raw,
      values: {
        woundsMax: minOne(raw.woundsMax),
        shock: minOne(raw.shock),
        determination: minOne(raw.determination),
        defence: minOne(raw.defence),
        resilience: minOne(raw.resilience),
        resolve: minOne(raw.resolve),
        conviction: minOne(raw.conviction),
        influence: minOne(raw.influence),
        wealth: minOne(raw.wealth),
        corruption: minZero(raw.corruption),
        speed: minOne(raw.speed),
        passiveAwareness: minOne(raw.passiveAwareness)
      },
      attrs: attrs,
      skills: skillValues,
      skillTotals: skillTotals,
      character: character,
      rules: rules,
      entries: buildTextEntries(rules)
    };
  }

  function compactEntry(text){
    return String(text || '')
      .split('\n')
      .map(function(line){ return line.trim(); })
      .filter(Boolean)
      .join(' / ');
  }

  function buildTextEntries(rules){
    const abilitiesAndTalents = [];
    const notes = [];
    const background = [];

    getTalents().forEach(function(talent){
      const entry = compactEntry(talent.name);
      if (entry) abilitiesAndTalents.push(entry);
    });

    rules.forEach(function(rule){
      const entry = compactEntry(rule.name);
      if (!entry) return;

      if (rule.type === 'backgroundBonus') {
        background.push(entry);
        return;
      }

      if (rule.type === 'archetypeAbility') {
        if (rule.target === 'none') abilitiesAndTalents.push(entry);
        else notes.push(entry);
        return;
      }

      notes.push(entry);
    });

    return { abilitiesAndTalents: abilitiesAndTalents, notes: notes, background: background };
  }

  function setTextField(form, name, value, font, warnings, skipBlank){
    const text = String(value == null ? '' : value);
    if (skipBlank !== false && text.trim() === '') return;

    try {
      const field = form.getTextField(name);
      field.setText(text);
      if (field.setFontSize) {
        const len = text.length;
        const size = len > 900 ? 5 : len > 650 ? 6 : len > 420 ? 7 : len > 240 ? 8 : 10;
        try { field.setFontSize(size); } catch (error) {}
      }
      if (font && field.updateAppearances) {
        try { field.updateAppearances(font); } catch (error) { warnings.push('Could not set font for field ' + name + ': ' + error.message); }
      }
    } catch (error) {
      warnings.push('Missing PDF field: ' + name);
    }
  }

  function clearAndRemoveTextField(form, name, font){
    try {
      const field = form.getTextField(name);
      try { field.setText(''); } catch (error) {}
      try { if (font && field.updateAppearances) field.updateAppearances(font); } catch (error) {}
      try { form.removeField(field); } catch (error) {}
    } catch (error) {}
  }

  function setCheckBox(form, name, checked, warnings){
    try {
      const field = form.getCheckBox(name);
      if (checked) field.check();
      else field.uncheck();
      if (field.updateAppearances) field.updateAppearances();
    } catch (error) {
      warnings.push('Missing PDF checkbox: ' + name);
    }
  }

  function loadPolishFont(pdfDoc){
    if (!window.fontkit) throw new Error('Missing fontkit. Check Kalkulator/vendor/pdf-lib.min.js.');
    pdfDoc.registerFontkit(window.fontkit);
    return fetch(FONT_URL).then(function(response){
      if (!response.ok) throw new Error('Could not fetch Noto Sans Regular font.');
      return response.arrayBuffer();
    }).then(function(bytes){
      return pdfDoc.embedFont(bytes, { subset: false });
    });
  }

  function wrapTextToWidth(text, font, fontSize, maxWidth, prefix, hangingPrefix){
    const words = String(text || '').split(/\s+/).filter(Boolean);
    const lines = [];
    let line = prefix || '';
    const indent = hangingPrefix || '';

    function width(value){ return font.widthOfTextAtSize(value, fontSize); }
    function pushLine(){
      if (line.trim()) lines.push(line);
      line = indent;
    }

    words.forEach(function(word){
      const candidate = line.trim() ? line + ' ' + word : line + word;
      if (width(candidate) <= maxWidth) {
        line = candidate;
        return;
      }

      if (line.trim()) pushLine();

      if (width(indent + word) <= maxWidth) {
        line = indent + word;
        return;
      }

      let chunk = '';
      for (const char of word) {
        if (width(indent + chunk + char) > maxWidth && chunk) {
          lines.push(indent + chunk);
          chunk = char;
        } else {
          chunk += char;
        }
      }
      line = indent + chunk;
    });

    if (line.trim()) lines.push(line);
    return lines;
  }

  function layoutColumnText(entries, area, font){
    const gutter = area.gutter == null ? 10 : area.gutter;
    const normalized = entries.map(function(entry){ return compactEntry(entry); }).filter(Boolean);

    for (let columns = area.minColumns; columns <= area.maxColumns; columns++) {
      for (let fontSize = area.maxFontSize; fontSize >= area.minFontSize; fontSize--) {
        const colWidth = (area.width - gutter * (columns - 1)) / columns;
        const lineHeight = fontSize * 1.18;
        const linesPerColumn = Math.floor(area.height / lineHeight);
        const allLines = [];

        normalized.forEach(function(entry){
          const lines = wrapTextToWidth(entry, font, fontSize, colWidth, '- ', '  ');
          allLines.push.apply(allLines, lines);
        });

        if (allLines.length <= linesPerColumn * columns) {
          return { columns: columns, fontSize: fontSize, lineHeight: lineHeight, linesPerColumn: linesPerColumn, colWidth: colWidth, lines: allLines, omitted: 0 };
        }
      }
    }

    const columns = area.maxColumns;
    const fontSize = area.minFontSize;
    const colWidth = (area.width - gutter * (columns - 1)) / columns;
    const lineHeight = fontSize * 1.18;
    const linesPerColumn = Math.floor(area.height / lineHeight);
    const capacity = linesPerColumn * columns;
    const allLines = [];

    normalized.forEach(function(entry){
      const lines = wrapTextToWidth(entry, font, fontSize, colWidth, '- ', '  ');
      allLines.push.apply(allLines, lines);
    });

    return { columns: columns, fontSize: fontSize, lineHeight: lineHeight, linesPerColumn: linesPerColumn, colWidth: colWidth, lines: allLines.slice(0, capacity), omitted: Math.max(0, allLines.length - capacity) };
  }

  function drawColumnText(pdfDoc, entries, area, font, warnings){
    if (!entries || !entries.length) return;

    const page = pdfDoc.getPages()[area.pageIndex];
    if (!page) {
      warnings.push(area.label + ': missing PDF page ' + area.pageIndex + '.');
      return;
    }

    const layout = layoutColumnText(entries, area, font);
    const color = window.PDFLib.rgb(0, 0, 0);
    const gutter = area.gutter == null ? 10 : area.gutter;

    layout.lines.forEach(function(line, index){
      const column = Math.floor(index / layout.linesPerColumn);
      const row = index % layout.linesPerColumn;
      const x = area.x + column * (layout.colWidth + gutter);
      const y = area.y + area.height - layout.fontSize - row * layout.lineHeight;
      page.drawText(line, { x: x, y: y, size: layout.fontSize, font: font, color: color });
    });

    if (layout.omitted > 0) {
      warnings.push(area.label + ': tekst przekracza dostępny obszar. Pominięto ' + layout.omitted + ' linii po automatycznym doborze ' + layout.columns + ' kolumn i fontu ' + layout.fontSize + '.');
    }
  }

  function removeOldLargeTextFields(form, font){
    ABILITY_FIELD_NAMES.forEach(function(name){ clearAndRemoveTextField(form, name, font); });
    clearAndRemoveTextField(form, 'Notatki 1', font);
    clearAndRemoveTextField(form, 'Przeszłość', font);
  }

  function fillStandardPdfFields(form, data, font, warnings){
    const values = data.values;
    const character = data.character;

    setTextField(form, 'Poziom', character.gameTier, font, warnings, false);
    setTextField(form, 'Gatunek', character.speciesName, font, warnings);
    setTextField(form, 'Archetyp', character.archetypeName, font, warnings);
    setTextField(form, 'Frakcja', character.factionName, font, warnings);
    setTextField(form, 'Słowa Kluczowe', character.keywords, font, warnings);
    setTextField(form, 'Rozmiar', character.size, font, warnings, false);
    setTextField(form, 'Szybkość', values.speed, font, warnings, false);

    ['S', 'Wt', 'Zr', 'I', 'SW', 'Int', 'Ogd'].forEach(function(key){
      setTextField(form, key, data.attrs[key], font, warnings, false);
    });

    SKILLS.forEach(function(skill){
      setTextField(form, skill.pdf, data.skills[skill.key], font, warnings, false);
      setTextField(form, skill.sum, data.skillTotals[skill.key], font, warnings, false);
    });

    setTextField(form, 'Upór', values.resolve, font, warnings, false);
    setTextField(form, 'Odwaga', values.conviction, font, warnings, false);
    setTextField(form, 'Obrona', values.defence, font, warnings, false);
    setTextField(form, 'Bazowa Odporność', values.resilience, font, warnings, false);
    setTextField(form, 'Maksymalna Żywotność', values.woundsMax, font, warnings, false);
    setTextField(form, 'Odporność Psychiczna', values.shock, font, warnings, false);
    setTextField(form, 'Determinacja', values.determination, font, warnings, false);
    setTextField(form, 'Wpływy', values.influence, font, warnings, false);
    setTextField(form, 'Majątek', values.wealth, font, warnings, false);
    setTextField(form, 'Pasywna Czujność', values.passiveAwareness, font, warnings, false);

    CORRUPTION_SLOTS.forEach(function(name, index){
      setCheckBox(form, name, index < values.corruption, warnings);
    });

    const levelMarks = Math.max(0, Math.min(4, Math.ceil(((Number(values.corruption) || 0) - 5) / 5)));
    CORRUPTION_LEVEL_SLOTS.forEach(function(name, index){
      setCheckBox(form, name, index < levelMarks, warnings);
    });
  }

  function openPreviewWindow(){
    const previewWindow = window.open('', '_blank');
    if (previewWindow) {
      previewWindow.document.write('<!doctype html><html><head><meta charset="utf-8"><title>Generating PDF...</title></head><body style="margin:24px;background:#000;color:#9cf09c;font-family:Consolas,monospace;">The Machine Canticle is rendering the PDF preview...</body></html>');
      previewWindow.document.close();
    }
    return previewWindow;
  }

  function exportColumnPdf(previewWindow){
    const warnings = [];

    if (!window.PDFLib || !window.PDFLib.PDFDocument) {
      const msg = 'Missing PDFLib. Add local file Kalkulator/vendor/pdf-lib.min.js.';
      setPdfLog(msg, 'error');
      showPreviewError(previewWindow, msg);
      return Promise.resolve();
    }

    const data = computeData();

    return fetch('./pdf/pl.pdf')
      .then(function(response){
        if (!response.ok) throw new Error('Could not fetch ./pdf/pl.pdf');
        return response.arrayBuffer();
      })
      .then(function(bytes){ return window.PDFLib.PDFDocument.load(bytes); })
      .then(function(pdfDoc){
        return loadPolishFont(pdfDoc).then(function(font){
          const form = pdfDoc.getForm();

          fillStandardPdfFields(form, data, font, warnings);
          removeOldLargeTextFields(form, font);
          drawColumnText(pdfDoc, data.entries.abilitiesAndTalents, COLUMN_AREAS.abilitiesAndTalents, font, warnings);
          drawColumnText(pdfDoc, data.entries.notes, COLUMN_AREAS.notes, font, warnings);
          drawColumnText(pdfDoc, data.entries.background, COLUMN_AREAS.background, font, warnings);

          return pdfDoc.save({ updateFieldAppearances: false }).then(function(out){
            const fileName = buildPdfFileName('PL');
            const pdfFile = window.File ? new File([out], fileName, { type: 'application/pdf' }) : new Blob([out], { type: 'application/pdf' });
            const url = URL.createObjectURL(pdfFile);

            if (previewWindow && !previewWindow.closed) {
              previewWindow.document.title = fileName;
              previewWindow.location.replace(url);
            } else {
              const opened = window.open(url, '_blank');
              if (!opened) setPdfLog('PDF generated, but the browser blocked the preview window. Allow pop-ups for this page and try again.', 'error');
            }

            setTimeout(function(){ URL.revokeObjectURL(url); }, 300000);
            const okMessage = 'PDF generated with dynamic column layout for Zdolności i Talenty, Notatki and Przeszłość.';
            setPdfLog(warnings.length ? warnings.join('\n') : okMessage, warnings.length ? 'warn' : 'ok');
          });
        });
      })
      .catch(function(error){
        console.error(error);
        const message = error.stack || error.message;
        setPdfLog(message, 'error');
        showPreviewError(previewWindow, message);
      });
  }

  document.addEventListener('click', function(event){
    const button = event.target && event.target.closest ? event.target.closest('#exportCharacterPdfButton') : null;
    if (!button) return;

    event.preventDefault();
    event.stopPropagation();
    if (event.stopImmediatePropagation) event.stopImmediatePropagation();

    const previewWindow = openPreviewWindow();
    exportColumnPdf(previewWindow);
  }, true);
})();
